wms_height = #{wmsHeight}, wms_height_bs = #{wmsHeightBs}, wms_length = #{wmsLength}, wms_length_bs = #{wmsLengthBs}, wms_weight = #{wmsWeight}, wms_weight_bs = #{wmsWeightBs}, wms_width = #{wmsWidth}, wms_width_bs = #{wmsWidthBs}, source_payload_json = #{sourcePayloadJson}, source_payload_hash = #{sourcePayloadHash}, update_time = sysdate()
