mapper.update:
update upstream_system_sku_candidate
set status = 'MISSING',
    update_time = sysdate()
where connection_code = #{connectionCode}
  and sync_batch_id <> #{syncBatchId}

mapper.select:
select min(c.connection_code) as connection_code, as source_sku_group_key, as source_dimension_group_key, as source_group_key, max(case when conn.system_kind = 'LINGXING_WMS' then 'lingxing-wms' else conn.system_kind end) as system_kind, group_concat(distinct conn.master_warehouse_name order by conn.master_warehouse_name separator ' / ') as master_warehouse_name, group_concat(distinct c.connection_code order by c.connection_code separator ',') as source_connection_codes, group_concat(distinct conn.master_warehouse_name order by conn.master_warehouse_name separator ' / ') as source_warehouse_names, count(distinct c.connection_code) as warehouse_count, count(1) as source_row_count, c.master_sku, c.master_product_name, max(c.product_alias_name) as product_alias_name, max(c.approve_status) as approve_status, max(c.product_type) as product_type, max(c.product_description) as product_description, max(c.image_url) as image_url, max(c.main_code) as main_code, max(c.other_code) as other_code, max(c.fnsku) as fnsku, max(c.country_of_origin_name) as country_of_origin_name, max(c.currency_code) as currency_code, max(c.customhouse_code) as customhouse_code, max(c.dangerous_cargo) as dangerous_cargo, max(c.declare_name_cn) as declare_name_cn, max(c.declare_name_en) as declare_name_en, max(c.declare_price) as declare_price, c.product_height, max(c.product_height_bs) as product_height_bs, c.product_length, max(c.product_length_bs) as product_length_bs, c.product_weight, max(c.product_weight_bs) as product_weight_bs, c.product_width, max(c.product_width_bs) as product_width_bs, c.wms_height, max(c.wms_height_bs) as wms_height_bs, c.wms_length, max(c.wms_length_bs) as wms_length_bs, c.wms_weight, max(c.wms_weight_bs) as wms_weight_bs, c.wms_width, max(c.wms_width_bs) as wms_width_bs, max(c.cat1_name) as cat1_name, max(c.cat2_name) as cat2_name, max(c.cat3_name) as cat3_name, max(c.platform_sku_info_json) as platform_sku_info_json, max(c.brazil_tax_info_json) as brazil_tax_info_json, max(c.source_payload_hash) as source_payload_hash, case when count(distinct c.status) = 1 then max(c.status) else 'MIXED' end as status, max(c.search_text) as search_text, max(c.sync_batch_id) as sync_batch_id, min(c.first_seen_time) as first_seen_time, max(c.last_seen_time) as last_seen_time, max(c.update_time) as update_time, case when sum(case when p.sku_pairing_id is not null then 1 else 0 end) = 0 then 'UNASSIGNED' when sum(case when p.sku_pairing_id is not null then 1 else 0 end) = count(1) then 'PAIRED' else 'PARTIAL' end as pairing_status, max(p.sku_pairing_id) as sku_pairing_id, group_concat(distinct nullif(p.system_sku, '') order by p.system_sku separator ' / ') as system_sku, group_concat(distinct nullif(p.system_sku_name, '') order by p.system_sku_name separator ' / ') as system_sku_name, group_concat(distinct nullif(p.customer_name, '') order by p.customer_name separator ' / ') as customer_name from upstream_system_sku_candidate c inner join upstream_system_connection conn on conn.connection_code = c.connection_code left join upstream_system_sku_pairing p on p.connection_code = c.connection_code and p.master_sku = c.master_sku where 1 = 1
and 1 = 0
and (conn.system_kind = 'lingxing-wms' or conn.system_kind = 'LINGXING_WMS')
and c.connection_code = #{connectionCode}
and = #{sourceSkuGroupKey}
and ( conn.system_kind = #{systemKind}
or conn.system_kind = 'LINGXING_WMS'
)
and conn.master_warehouse_name like concat('%', #{masterWarehouseName}, '%')
and c.master_sku like concat('%', #{masterSku}, '%')
and ( c.master_product_name like concat('%', #{productName}, '%') or c.product_alias_name like concat('%', #{productName}, '%') or c.product_description like concat('%', #{productName}, '%') )
and ( c.main_code like concat('%', #{identifyCodeKeyword}, '%') or c.other_code like concat('%', #{identifyCodeKeyword}, '%') or c.fnsku like concat('%', #{identifyCodeKeyword}, '%') )
and ( c.cat1_name like concat('%', #{categoryKeyword}, '%') or c.cat2_name like concat('%', #{categoryKeyword}, '%') or c.cat3_name like concat('%', #{categoryKeyword}, '%') )
and c.approve_status = #{approveStatus}
and c.dangerous_cargo = #{dangerousCargo}
and c.status = #{status}
and p.sku_pairing_id is not null
and p.sku_pairing_id is null
and ( c.search_text like concat('%', #{keyword}, '%') or c.connection_code like concat('%', #{keyword}, '%') or conn.master_warehouse_name like concat('%', #{keyword}, '%') or p.system_sku like concat('%', #{keyword}, '%') or p.system_sku_name like concat('%', #{keyword}, '%') or p.customer_name like concat('%', #{keyword}, '%') )
group by c.master_sku, c.master_product_name, c.product_length, c.product_width, c.product_height, c.product_weight, c.wms_length, c.wms_width, c.wms_height, c.wms_weight order by max(c.update_time) desc, c.master_sku asc

mapper.update:
update upstream_system_sku_inventory_snapshot
set status = 'MISSING',
    update_time = sysdate()
where connection_code = #{connectionCode}
  and sync_batch_id <> #{syncBatchId}

mapper.select:
select s.*, c.system_kind, c.master_warehouse_name, case when nullif(s.system_warehouse_code, '') is null then 'UNASSIGNED' else 'PAIRED' end as warehouse_pairing_status, case when nullif(s.system_sku, '') is null then 'UNASSIGNED' else 'PAIRED' end as sku_pairing_status from upstream_system_sku_inventory_snapshot s left join upstream_system_connection c on c.connection_code = s.connection_code where 1 = 1
and s.connection_code = #{connectionCode}
and s.status = #{status}
and s.inventory_scope = #{inventoryScope}
and s.inventory_attribute = #{inventoryAttribute}
and ( s.upstream_warehouse_code like concat('%', #{warehouseKeyword}, '%') or s.upstream_warehouse_name like concat('%', #{warehouseKeyword}, '%') or s.system_warehouse_code like concat('%', #{warehouseKeyword}, '%') or s.system_warehouse_name like concat('%', #{warehouseKeyword}, '%') )
and nullif(s.system_warehouse_code, '') is not null
and nullif(s.system_warehouse_code, '') is null
and nullif(s.system_sku, '') is not null
and nullif(s.system_sku, '') is null
and ( s.master_sku like concat('%', #{keyword}, '%') or s.master_product_name like concat('%', #{keyword}, '%') or s.system_sku like concat('%', #{keyword}, '%') or s.system_sku_name like concat('%', #{keyword}, '%') or s.customer_name like concat('%', #{keyword}, '%') )
order by s.update_time desc, s.upstream_warehouse_code asc, s.master_sku asc

select *
from upstream_system_sku_candidate
where connection_code = #{connectionCode}
  and master_sku = #{masterSku}
limit 1

